/**
 * Telemetry JSONL Schemas — contract lock for downstream consumers
 *
 * The hooks under M119 (#1469, #1470, #1478) write append-only JSONL
 * files that downstream issues consume:
 *
 *   .claude/telemetry/pre-compact-decisions.jsonl  ← #1476 outcome tracker
 *   .claude/telemetry/image-responses.jsonl        ← #1479 cache-aware nudge
 *
 * If a writer changes a field name or makes a required field optional,
 * consumers break silently. This module defines the canonical shape of
 * each entry and a pure `isValidX` predicate used by test snapshots
 * to lock the contract.
 *
 * Hand-rolled (no Zod dep in src/hooks/). Shape checks are structural:
 * required keys present + types match.
 */

// ---------------------------------------------------------------------------
// ImageResponseEntry — written by posttool/context-crossing-warn
// ---------------------------------------------------------------------------

export interface ImageResponseEntry {
  /** ISO-8601 timestamp of when the image response was observed */
  timestamp: string;
  /** Tool that produced the image output (e.g., "Read", "Agent", "mcp__fal__generate_image") */
  tool: string;
  /** Character length of the raw payload (not a token estimate — images are tokenized model-side) */
  char_len: number;
}

export const IMAGE_RESPONSE_REQUIRED_KEYS: ReadonlyArray<keyof ImageResponseEntry> = [
  'timestamp',
  'tool',
  'char_len',
];

export function isValidImageResponseEntry(raw: unknown): raw is ImageResponseEntry {
  if (!raw || typeof raw !== 'object') return false;
  const entry = raw as Record<string, unknown>;
  if (typeof entry.timestamp !== 'string') return false;
  if (typeof entry.tool !== 'string') return false;
  if (typeof entry.char_len !== 'number' || !Number.isFinite(entry.char_len)) return false;
  // Timestamp must parse as a real date
  if (Number.isNaN(Date.parse(entry.timestamp))) return false;
  return true;
}

// ---------------------------------------------------------------------------
// PreCompactDecisionEntry — written by lifecycle/pre-compact-task-done-prompt
// ---------------------------------------------------------------------------

export interface PreCompactDecisionSignals {
  gitQuiet: boolean;
  quiescent: boolean;
  breakpointKeywords: boolean;
}

export interface PreCompactDecisionEntry {
  /** ISO-8601 timestamp of the PreCompact event */
  timestamp: string;
  /** Whether the hook blocked compaction (fired=true) or allowed it through */
  fired: boolean;
  /** The three heuristic signal states at fire-check time */
  signals: PreCompactDecisionSignals;
  /** True when the check was skipped due to cooldown */
  cooldown?: boolean;
  /** True when the check was skipped due to ORK_NO_PRECOMPACT_PROMPT=1 */
  optOut?: boolean;
}

export const PRE_COMPACT_DECISION_REQUIRED_KEYS: ReadonlyArray<keyof PreCompactDecisionEntry> = [
  'timestamp',
  'fired',
  'signals',
];

export const PRE_COMPACT_SIGNAL_KEYS: ReadonlyArray<keyof PreCompactDecisionSignals> = [
  'gitQuiet',
  'quiescent',
  'breakpointKeywords',
];

export function isValidPreCompactDecisionEntry(raw: unknown): raw is PreCompactDecisionEntry {
  if (!raw || typeof raw !== 'object') return false;
  const entry = raw as Record<string, unknown>;
  if (typeof entry.timestamp !== 'string') return false;
  if (Number.isNaN(Date.parse(entry.timestamp))) return false;
  if (typeof entry.fired !== 'boolean') return false;
  if (!entry.signals || typeof entry.signals !== 'object') return false;
  const sig = entry.signals as Record<string, unknown>;
  for (const key of PRE_COMPACT_SIGNAL_KEYS) {
    if (typeof sig[key] !== 'boolean') return false;
  }
  if (entry.cooldown !== undefined && typeof entry.cooldown !== 'boolean') return false;
  if (entry.optOut !== undefined && typeof entry.optOut !== 'boolean') return false;
  return true;
}

// ---------------------------------------------------------------------------
// DecisionLogEntry — .claude/logs/decisions.jsonl (M121 #1490)
// Written by various hooks; read by pre-compact-task-done-prompt,
// handoff-writer (stop/), decision-history, /ork:analytics.
// Shape is permissive because multiple writers have contributed over time —
// core invariant is that either `summary` or `decision` is a string readers
// can display.
// ---------------------------------------------------------------------------

export interface DecisionLogEntry {
  /** Human-readable one-line decision summary (preferred field for display) */
  summary?: string;
  /** Legacy field name for the same thing; readers fall back to this */
  decision?: string;
  /** ISO-8601 timestamp (not always present on legacy entries) */
  timestamp?: string;
  /** Optional categorisation: 'feat' | 'fix' | 'architecture' | ... */
  kind?: string;
  /** Free-form extra payload */
  [key: string]: unknown;
}

export function isValidDecisionLogEntry(raw: unknown): raw is DecisionLogEntry {
  if (!raw || typeof raw !== 'object') return false;
  const entry = raw as Record<string, unknown>;
  // Invariant: at least one of summary or decision must be a non-empty string
  const hasSummary = typeof entry.summary === 'string' && entry.summary.length > 0;
  const hasDecision = typeof entry.decision === 'string' && entry.decision.length > 0;
  if (!hasSummary && !hasDecision) return false;
  // If timestamp present, it must parse
  if (entry.timestamp !== undefined) {
    if (typeof entry.timestamp !== 'string') return false;
    if (Number.isNaN(Date.parse(entry.timestamp))) return false;
  }
  if (entry.kind !== undefined && typeof entry.kind !== 'string') return false;
  return true;
}

// ---------------------------------------------------------------------------
// SubagentSpawnEntry — .claude/logs/subagent-spawns.jsonl (M121 #1490)
// Written by subagent-start hooks; read by pre-compact-guard, watchdog,
// pre-compact-task-done-prompt (quiescence signal).
// ---------------------------------------------------------------------------

export interface SubagentSpawnEntry {
  /** ISO-8601 timestamp of the spawn event */
  timestamp: string;
  /**
   * Which event wrote the entry: 'pretool' = spawn-intent-logger at
   * PreToolUse[Task] (carries description; no agent_id), 'start' =
   * subagent-validator at SubagentStart (carries agent_id; CC 2.1.173 sends
   * no description there — live-verified). Entries before 2026-06-11 have
   * neither tag. CC provides no field to correlate the two.
   */
  source?: 'pretool' | 'start';
  /** Agent identifier (UUID or name) */
  agent_id?: string;
  /** PreToolUse tool_use_id (CC 2.1.69) — present on source:'pretool' entries */
  tool_use_id?: string;
  /** Agent type (e.g., 'Explore', 'workflow-architect') */
  subagent_type?: string;
  /** Task summary — Agent tool description, else first line of the prompt (max 200 chars) */
  description?: string;
  /** Spawning agent's ID — present when the spawn is nested (CC 2.1.139 input field; chains execute since CC 2.1.172) */
  parent_agent_id?: string;
  /** 1-based nesting depth: 1 = spawned by the main loop, 2+ = nested (CC 2.1.172 allows up to 5) */
  spawn_depth?: number;
}

export const SUBAGENT_SPAWN_REQUIRED_KEYS: ReadonlyArray<keyof SubagentSpawnEntry> = [
  'timestamp',
];

export function isValidSubagentSpawnEntry(raw: unknown): raw is SubagentSpawnEntry {
  if (!raw || typeof raw !== 'object') return false;
  const entry = raw as Record<string, unknown>;
  if (typeof entry.timestamp !== 'string') return false;
  if (Number.isNaN(Date.parse(entry.timestamp))) return false;
  if (entry.agent_id !== undefined && typeof entry.agent_id !== 'string') return false;
  if (entry.subagent_type !== undefined && typeof entry.subagent_type !== 'string') return false;
  if (entry.description !== undefined && typeof entry.description !== 'string') return false;
  if (entry.source !== undefined && entry.source !== 'pretool' && entry.source !== 'start') return false;
  if (entry.tool_use_id !== undefined && typeof entry.tool_use_id !== 'string') return false;
  if (entry.parent_agent_id !== undefined && typeof entry.parent_agent_id !== 'string') return false;
  if (
    entry.spawn_depth !== undefined &&
    (typeof entry.spawn_depth !== 'number' || !Number.isInteger(entry.spawn_depth) || entry.spawn_depth < 1)
  ) {
    return false;
  }
  return true;
}

// ---------------------------------------------------------------------------
// SkillChannelEntry — .claude/logs/skill-channels.jsonl (activation channels)
// Written by pretool/skill/skill-tracker (channel:"main") and
// subagent-stop/skill-channel-tracker (channel:"subagent"). Each row records
// one Skill invocation tagged with the activation channel it fired through, so
// the activation matrix can be computed from real telemetry rather than static
// analysis. `chain` and `background` are reserved for future capture points.
// ---------------------------------------------------------------------------

export type SkillChannel = 'main' | 'subagent' | 'chain' | 'background';

export interface SkillChannelEntry {
  /** ISO-8601 timestamp of the invocation */
  ts: string;
  /** Skill name as invoked (e.g. 'ork:cover') */
  skill: string;
  /** Activation channel the invocation fired through */
  channel: SkillChannel;
  /** Parent that triggered it: subagent_type for 'subagent', skill for 'chain' */
  parent?: string;
  /** Originating session id, when available */
  session_id?: string;
}

const SKILL_CHANNELS: ReadonlyArray<SkillChannel> = ['main', 'subagent', 'chain', 'background'];

export const SKILL_CHANNEL_REQUIRED_KEYS: ReadonlyArray<keyof SkillChannelEntry> = [
  'ts',
  'skill',
  'channel',
];

export function isValidSkillChannelEntry(raw: unknown): raw is SkillChannelEntry {
  if (!raw || typeof raw !== 'object') return false;
  const entry = raw as Record<string, unknown>;
  if (typeof entry.ts !== 'string' || Number.isNaN(Date.parse(entry.ts))) return false;
  if (typeof entry.skill !== 'string' || entry.skill.length === 0) return false;
  if (typeof entry.channel !== 'string' || !SKILL_CHANNELS.includes(entry.channel as SkillChannel)) return false;
  if (entry.parent !== undefined && typeof entry.parent !== 'string') return false;
  if (entry.session_id !== undefined && typeof entry.session_id !== 'string') return false;
  return true;
}

